<?php
error_reporting(0);ini_set('display_errors',0);
define('MODULE_DIR','/data/adb/QTUN');define('MODULE_SCRIPTS_DIR','/data/adb/QTUN/scripts');
define('USERS_FILE','/data/adb/php7/files/www/data/users.json');define('TOKENS_FILE','/data/adb/php7/files/www/data/tokens.json');
$api_route=$_GET['api']??$_POST['api']??null;$method=$_SERVER['REQUEST_METHOD'];
function json_response($d){header('Content-Type: application/json; charset=utf-8');echo json_encode($d,JSON_UNESCAPED_UNICODE);exit;}
function get_input(){if($_SERVER['REQUEST_METHOD']==='POST')return json_decode(file_get_contents('php://input'),true)??[];return $_GET;}
function is_api_request(){return isset($_GET['api'])||isset($_POST['api'])||(isset($_SERVER['HTTP_ACCEPT'])&&strpos($_SERVER['HTTP_ACCEPT'],'application/json')!==false);}
function load_users(){if(!file_exists(USERS_FILE)){$du=['admin'=>['password'=>'admin123','role'=>'admin']];file_put_contents(USERS_FILE,json_encode($du,JSON_PRETTY_PRINT));chmod(USERS_FILE,0600);return $du;}return json_decode(file_get_contents(USERS_FILE),true);}
function save_users($u){file_put_contents(USERS_FILE,json_encode($u,JSON_PRETTY_PRINT));chmod(USERS_FILE,0600);}
function verify_user($u,$p){$users=load_users();return isset($users[$u])&&$users[$u]['password']===$p;}
function load_tokens(){if(!file_exists(TOKENS_FILE)){$dir=dirname(TOKENS_FILE);if(!is_dir($dir))mkdir($dir,0755,true);file_put_contents(TOKENS_FILE,json_encode([]));chmod(TOKENS_FILE,0600);return[];}return json_decode(file_get_contents(TOKENS_FILE),true);}
function save_tokens($t){file_put_contents(TOKENS_FILE,json_encode($t));chmod(TOKENS_FILE,0600);}
function generate_token($u){$t=load_tokens();foreach($t as $k=>$v)if($v['username']===$u)unset($t[$k]);$token=bin2hex(random_bytes(32));$t[$token]=['username'=>$u,'expires'=>time()+7*24*3600];save_tokens($t);return $token;}
function verify_token($token){$t=load_tokens();if(isset($t[$token])){$d=$t[$token];if($d['expires']>time())return $d['username'];else{unset($t[$token]);save_tokens($t);}}return false;}
function delete_token($token){$t=load_tokens();if(isset($t[$token])){unset($t[$token]);save_tokens($t);return true;}return false;}
function root_exec($c){$cmd="su -c ".escapeshellarg($c)." 2>&1";exec($cmd,$o,$rc);return['output'=>implode("\n",$o),'code'=>$rc];}
function get_config_dir(){$v1=MODULE_DIR.'/config';$v2=MODULE_DIR.'/libuz';if(is_dir($v1))return$v1;if(is_dir($v2))return$v2;return$v1;}
function qtun_status(){$disable=MODULE_DIR.'/disable';if(file_exists($disable))return['status'=>'Offline','reason'=>'Module disabled'];$pidf=MODULE_DIR.'/run/qtun.pid';if(!file_exists($pidf))return['status'=>'Offline','reason'=>'PID file not found'];$pid=trim(file_get_contents($pidf));if(empty($pid))return['status'=>'Offline','reason'=>'Empty PID'];$res=root_exec("ps -p $pid -o pid= 2>/dev/null");if(trim($res['output'])==='')return['status'=>'Offline','reason'=>'Process not running'];$sf=MODULE_DIR.'/run/status';if(file_exists($sf)){$sc=trim(file_get_contents($sf));if($sc==='running'||$sc==='online')return['status'=>'Online','reason'=>'Status file: '.$sc];}$pc=root_exec("netstat -tulpn 2>/dev/null | grep ':7777' || ss -tulpn 2>/dev/null | grep ':7777'");if(trim($pc['output'])!=='')return['status'=>'Online','reason'=>'Port 7777 listening'];return['status'=>'Online','reason'=>'Process running'];}
function qtun_action($a){switch($a){case'start':$cmd='sh '.MODULE_SCRIPTS_DIR.'/webui.sh start';break;case'stop':$cmd='sh '.MODULE_SCRIPTS_DIR.'/webui.sh stop';break;case'restart':$cmd='sh '.MODULE_SCRIPTS_DIR.'/webui.sh restart';break;default:return['success'=>false,'message'=>'Invalid action'];} $r=root_exec($cmd);sleep(2);$sd=qtun_status();return['success'=>true,'message'=>$r['output']?:'Action completed','status'=>$sd['status'],'reason'=>$sd['reason']];}
function find_log_file(){$paths=[MODULE_DIR.'/run/run.log',MODULE_DIR.'/run/manager.log',MODULE_DIR.'/libuz/run.log','/data/adb/QTUN/run/run.log','/data/adb/QTUN/run/manager.log','/data/adb/QTUN/libuz/run.log','/data/adb/qtun/run/run.log','/data/adb/qtun/run/manager.log','/data/adb/qtun/libuz/run.log'];foreach($paths as $p)if(file_exists($p)&&is_readable($p))return$p;$res=root_exec("find /data/adb -iname 'run.log' -o -iname 'manager.log' 2>/dev/null | head -1");if(!empty(trim($res['output']))){$fp=trim($res['output']);if(file_exists($fp))return$fp;}return null;}
function qtun_logs($lines=50){$f=find_log_file();if(!$f)return "⚠️ Log file not found.\n\n📁 Checked paths:\n".implode("\n",[MODULE_DIR.'/run/run.log',MODULE_DIR.'/run/manager.log','/data/adb/qtun/run/run.log','/data/adb/QTUN/run/run.log']);$c=@file_get_contents($f);if($c===false){$r=root_exec("tail -n $lines ".escapeshellarg($f));if($r['code']===0)return$r['output'];return "⚠️ Cannot read log file: $f\n(Permission denied or file empty)";}$la=explode("\n",$c);$la=array_slice($la,-$lines);return implode("\n",$la);}
function get_active_config(){$paths=[MODULE_DIR.'/config/config.json',MODULE_DIR.'/config/active.json',MODULE_DIR.'/config.json',MODULE_DIR.'/libuz/config.json',MODULE_DIR.'/libuz/active.json','/data/adb/QTUN/config/config.json','/data/adb/QTUN/libuz/config.json'];foreach($paths as $p)if(file_exists($p))return basename($p);$r=root_exec("grep -r 'config' /proc/*/cmdline 2>/dev/null | grep -oE '[a-zA-Z0-9_-]+\.json' | head -1");if(!empty(trim($r['output'])))return trim($r['output']);return null;}
function get_configs(){$cd=get_config_dir();$files=[];$ac=get_active_config();if(is_dir($cd)){$dh=opendir($cd);while(($f=readdir($dh))!==false){if($f==='.'||$f==='..')continue;if($f==='users.json')continue;if(pathinfo($f,PATHINFO_EXTENSION)==='json'){$fp=$cd.'/'.$f;$files[]=['name'=>$f,'size'=>filesize($fp),'modified'=>date('Y-m-d H:i:s',filemtime($fp)),'is_active'=>($ac===$f)];}}closedir($dh);}return$files;}
function read_config($fn){$fn=basename($fn);$cd=get_config_dir();$fp=$cd.'/'.$fn;if(!file_exists($fp))return['success'=>false,'message'=>'File not found'];$ac=get_active_config();return['success'=>true,'content'=>file_get_contents($fp),'is_active'=>($ac===$fn)];}
function create_config($fn,$ct){$fn=basename($fn);if(!preg_match('/^[a-zA-Z0-9_-]+\.json$/',$fn))return['success'=>false,'message'=>'Invalid filename'];if($fn==='users.json')return['success'=>false,'message'=>'Cannot modify users.json'];json_decode($ct);if(json_last_error()!==JSON_ERROR_NONE)return['success'=>false,'message'=>'Invalid JSON: '.json_last_error_msg()];$cd=get_config_dir();if(!is_dir($cd))mkdir($cd,0755,true);$fp=$cd.'/'.$fn;if(file_exists($fp))return['success'=>false,'message'=>'File already exists'];$tmp='/data/local/tmp/qtun_'.$fn;file_put_contents($tmp,$ct);$r=root_exec("cp $tmp $fp && chmod 644 $fp && rm $tmp");if($r['code']!==0){if(file_put_contents($fp,$ct)===false)return['success'=>false,'message'=>'Failed to write file: '.$r['output']];chmod($fp,0644);}return['success'=>true,'message'=>'Config created successfully'];}
function update_config($fn,$ct){$fn=basename($fn);$cd=get_config_dir();$fp=$cd.'/'.$fn;if(!file_exists($fp))return['success'=>false,'message'=>'File not found'];if($fn==='users.json')return['success'=>false,'message'=>'Cannot modify users.json'];$ac=get_active_config();if($ac===$fn)return['success'=>false,'message'=>'Cannot edit config while it is in use by QTUN'];json_decode($ct);if(json_last_error()!==JSON_ERROR_NONE)return['success'=>false,'message'=>'Invalid JSON: '.json_last_error_msg()];$tmp='/data/local/tmp/qtun_'.$fn;file_put_contents($tmp,$ct);$r=root_exec("cp $tmp $fp && chmod 644 $fp && rm $tmp");if($r['code']!==0){if(file_put_contents($fp,$ct)===false)return['success'=>false,'message'=>'Failed to write file: '.$r['output']];chmod($fp,0644);}return['success'=>true,'message'=>'Config updated successfully'];}
function delete_config($fn){$fn=basename($fn);$cd=get_config_dir();$fp=$cd.'/'.$fn;if(!file_exists($fp))return['success'=>false,'message'=>'File not found'];if($fn==='users.json')return['success'=>false,'message'=>'Cannot delete users.json'];$ac=get_active_config();if($ac===$fn)return['success'=>false,'message'=>'Cannot delete config while it is in use by QTUN'];$r=root_exec("rm $fp");if($r['code']!==0)if(!unlink($fp))return['success'=>false,'message'=>'Failed to delete file'];return['success'=>true,'message'=>'Config deleted successfully'];}
if(is_api_request()){
    if($api_route==='login'){if($method!=='POST')json_response(['success'=>false,'message'=>'Method not allowed']);$in=get_input();if(!$in||!isset($in['username'])||!isset($in['password']))json_response(['success'=>false,'message'=>'Username and password required']);$u=trim($in['username']);$p=$in['password'];if(verify_user($u,$p)){$token=generate_token($u);json_response(['success'=>true,'username'=>$u,'token'=>$token]);}else json_response(['success'=>false,'message'=>'Invalid username or password']);}
    elseif($api_route==='verify_token'){if($method!=='POST')json_response(['success'=>false,'message'=>'Method not allowed']);$in=get_input();if(!isset($in['token']))json_response(['success'=>false,'message'=>'Token required']);$uname=verify_token($in['token']);if($uname)json_response(['success'=>true,'username'=>$uname]);else json_response(['success'=>false,'message'=>'Invalid or expired token']);}
    elseif($api_route==='logout'){if($method!=='POST')json_response(['success'=>false,'message'=>'Method not allowed']);$in=get_input();if(isset($in['token']))delete_token($in['token']);json_response(['success'=>true,'message'=>'Logged out']);}
    elseif($api_route==='status'){if($method!=='GET')json_response(['success'=>false,'message'=>'Method not allowed']);$sd=qtun_status();json_response(['success'=>true,'status'=>$sd['status'],'reason'=>$sd['reason']]);}
    elseif($api_route==='action'){if($method!=='POST')json_response(['success'=>false,'message'=>'Method not allowed']);$in=get_input();if(!$in||!isset($in['action']))json_response(['success'=>false,'message'=>'Action required']);json_response(qtun_action($in['action']));}
    elseif($api_route==='logs'){if($method==='GET')$lines=isset($_GET['lines'])?intval($_GET['lines']):100;elseif($method==='POST'){$in=get_input();$lines=isset($in['lines'])?intval($in['lines']):100;}else json_response(['success'=>false,'message'=>'Method not allowed']);$lines=max(1,min(500,$lines));$log=qtun_logs($lines);json_response(['success'=>true,'logs'=>$log]);}
    elseif($api_route==='host'){$host=$_SERVER['HTTP_HOST']??'localhost';$h=explode(':',$host)[0];json_response(['success'=>true,'host'=>$h]);}
    elseif($api_route==='configs'){if($method==='GET'){if(isset($_GET['action'])&&$_GET['action']==='list')json_response(['success'=>true,'configs'=>get_configs()]);if(isset($_GET['file'])){$fn=basename($_GET['file']);$cd=get_config_dir();$fp=$cd.'/'.$fn;if(!file_exists($fp))json_response(['success'=>false,'message'=>'File not found: '.$fn]);$ct=file_get_contents($fp);$ac=get_active_config();json_response(['success'=>true,'filename'=>$fn,'content'=>$ct,'size'=>filesize($fp),'modified'=>date('Y-m-d H:i:s',filemtime($fp)),'is_active'=>($ac===$fn)]);}json_response(['success'=>true,'configs'=>get_configs()]);}elseif($method==='POST'){$in=get_input();if(!isset($in['action']))json_response(['success'=>false,'message'=>'Action required']);switch($in['action']){case'create':if(!isset($in['filename'])||!isset($in['content']))json_response(['success'=>false,'message'=>'Filename and content required']);json_response(create_config($in['filename'],$in['content']));break;case'edit':if(!isset($in['filename'])||!isset($in['content']))json_response(['success'=>false,'message'=>'Filename and content required']);json_response(update_config($in['filename'],$in['content']));break;case'delete':if(!isset($in['filename']))json_response(['success'=>false,'message'=>'Filename required']);json_response(delete_config($in['filename']));break;case'read':if(!isset($in['filename']))json_response(['success'=>false,'message'=>'Filename required']);json_response(read_config($in['filename']));break;default:json_response(['success'=>false,'message'=>'Invalid action']);}}json_response(['success'=>false,'message'=>'Method not allowed']);}
    elseif($api_route==='users'){if($method==='GET'){$users=load_users();$ul=[];foreach($users as $u=>$d)$ul[]=['username'=>$u,'role'=>$d['role']];json_response(['success'=>true,'users'=>$ul]);}elseif($method==='POST'){$in=get_input();if(!isset($in['action']))json_response(['success'=>false,'message'=>'Action required']);$users=load_users();switch($in['action']){case'add':if(!isset($in['username'])||!isset($in['password']))json_response(['success'=>false,'message'=>'Username and password required']);$u=trim($in['username']);$p=$in['password'];if(empty($u)||empty($p))json_response(['success'=>false,'message'=>'Username and password cannot be empty']);if(isset($users[$u]))json_response(['success'=>false,'message'=>'User already exists']);if(strlen($p)<6)json_response(['success'=>false,'message'=>'Password must be at least 6 characters']);$users[$u]=['password'=>$p,'role'=>'user'];save_users($users);json_response(['success'=>true,'message'=>'User added successfully']);break;case'delete':if(!isset($in['username']))json_response(['success'=>false,'message'=>'Username required']);$u=trim($in['username']);if($u==='admin')json_response(['success'=>false,'message'=>'Cannot delete admin user']);if(!isset($users[$u]))json_response(['success'=>false,'message'=>'User not found']);unset($users[$u]);save_users($users);json_response(['success'=>true,'message'=>'User deleted successfully']);break;case'changepass':if(!isset($in['username'])||!isset($in['old_password'])||!isset($in['new_password']))json_response(['success'=>false,'message'=>'Username, old password and new password required']);$u=trim($in['username']);if(!isset($users[$u]))json_response(['success'=>false,'message'=>'User not found']);if($users[$u]['password']!==$in['old_password'])json_response(['success'=>false,'message'=>'Old password is incorrect']);if(strlen($in['new_password'])<6)json_response(['success'=>false,'message'=>'New password must be at least 6 characters']);$users[$u]['password']=$in['new_password'];save_users($users);json_response(['success'=>true,'message'=>'Password changed successfully']);break;default:json_response(['success'=>false,'message'=>'Invalid action']);}}json_response(['success'=>false,'message'=>'Method not allowed']);}
    json_response(['success'=>false,'message'=>'Unknown API endpoint']);
}
?>
