                <div class="d-flex justify-content-between flex-wrap flex-md-nowrap align-items-center pt-3 pb-2 mb-3 border-bottom animate__animated animate__fadeInDown"><h1 class="h2">Configuration</h1></div>
                <div class="row"><div class="col-lg-4 mb-4"><div class="card border-0 shadow-sm animate__animated animate__fadeInLeft"><div class="card-body"><div class="d-flex justify-content-between align-items-center mb-3"><h6 class="card-title text-uppercase text-muted mb-0">Config Files</h6><button class="btn btn-primary btn-sm" onclick="openCreateModal()"><i class="bi bi-plus-lg"></i> New</button></div><div id="configs-error" class="alert alert-danger d-none"></div><div id="configs-success" class="alert alert-success d-none"></div><div id="configs-list"></div></div></div></div>
                <div class="col-lg-8"><div class="card border-0 shadow-sm animate__animated animate__fadeInRight"><div class="card-body"><div id="editor-info" class="editor-info"><i class="bi bi-exclamation-triangle me-2"></i> Config is currently in use by QTUN. Stop the service to edit or delete.</div><div class="d-flex justify-content-between align-items-center mb-3"><h6 class="card-title text-uppercase text-muted mb-0" id="editor-title">Select a config file</h6><div id="editor-actions" style="display:none"><button class="btn btn-success btn-sm" id="btn-save-config" onclick="saveCurrentConfig()"><span class="btn-text"><i class="bi bi-check-lg"></i> Save</span><span class="spinner spinner-border spinner-border-sm"></span></button><button class="btn btn-outline-secondary btn-sm" onclick="reloadCurrentConfig()">Reload</button><button class="btn btn-danger btn-sm" id="btn-delete-config" onclick="deleteCurrentConfig()"><span class="btn-text"><i class="bi bi-trash"></i> Delete</span><span class="spinner spinner-border spinner-border-sm"></span></button></div></div><div id="editor-error" class="alert alert-danger d-none"></div><textarea class="form-control" id="config-editor" rows="20" placeholder="Select a configuration file from the list..." disabled></textarea></div></div></div></div>
            </div>
            <div class="page" id="page-clash">
                <div id="clash-container"></div>
            </div>
            <div class="page" id="page-users">
                <div class="d-flex justify-content-between flex-wrap flex-md-nowrap align-items-center pt-3 pb-2 mb-3 border-bottom animate__animated animate__fadeInDown"><h1 class="h2">User Management</h1></div>
                <div class="row"><div class="col-lg-6 mb-4"><div class="card border-0 shadow-sm h-100 animate__animated animate__fadeInLeft"><div class="card-body"><h6 class="card-title text-uppercase text-muted mb-3">User List</h6><div id="users-list"></div></div></div></div>
                <div class="col-lg-6"><div class="card border-0 shadow-sm mb-4 animate__animated animate__fadeInRight"><div class="card-body"><h6 class="card-title text-uppercase text-muted mb-3">Add User</h6><div id="users-error" class="alert alert-danger d-none"></div><div id="users-success" class="alert alert-success d-none"></div><div class="mb-3"><label class="form-label">Username</label><input type="text" class="form-control" id="new-username" placeholder="Enter username"></div><div class="mb-3"><label class="form-label">Password</label><input type="password" class="form-control" id="new-password" placeholder="Min 6 characters"></div><button class="btn btn-primary" onclick="addUser()" id="btn-add-user"><span class="btn-text">Add User</span><span class="spinner spinner-border spinner-border-sm"></span></button></div></div>
                <div class="card border-0 shadow-sm animate__animated animate__fadeInUp"><div class="card-body"><h6 class="card-title text-uppercase text-muted mb-3">Change Password</h6><div class="mb-3"><label class="form-label">Current Password</label><input type="password" class="form-control" id="old-pass" placeholder="Enter current password"></div><div class="mb-3"><label class="form-label">New Password</label><input type="password" class="form-control" id="new-pass" placeholder="Min 6 characters"></div><button class="btn btn-warning" onclick="changePassword()" id="btn-change-pass"><span class="btn-text">Update Password</span><span class="spinner spinner-border spinner-border-sm"></span></button></div></div></div></div>
            </div>
        </main>
    </div></div>
    <div class="modal fade" id="confirm-action-modal" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered modal-sm"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">Confirm</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><p id="confirm-action-message"></p></div><div class="modal-footer"><button class="btn btn-secondary" data-bs-dismiss="modal">Cancel</button><button class="btn btn-danger" id="confirm-action-ok">OK</button></div></div></div>
    </div>
    <div class="modal fade" id="delete-modal" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered modal-sm"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">Confirm Delete</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><p>Delete <strong id="delete-filename"></strong>?</p><small class="text-danger">This action cannot be undone.</small></div><div class="modal-footer"><button class="btn btn-secondary" data-bs-dismiss="modal">Cancel</button><button class="btn btn-danger" id="confirm-delete-btn">Delete</button></div></div></div>
    </div>
    <div class="modal fade" id="create-modal" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">New Configuration</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><div id="create-error" class="alert alert-danger d-none"></div><label class="form-label">Filename</label><input type="text" class="form-control" id="new-filename" placeholder="example.json"><small class="text-muted">Only a-z, 0-9, _, - allowed. Must end with .json</small></div><div class="modal-footer"><button class="btn btn-secondary" data-bs-dismiss="modal">Cancel</button><button class="btn btn-primary" onclick="createNewConfig()" id="btn-create-config">Create</button></div></div></div>
    </div>
    <script src="/bootstrap/js/bootstrap.bundle.min.js"></script>
    <script>
        let currentUser=null,currentConfigFile=null,isConfigActive=!1,refreshLogInterval=null,refreshStatusInterval=null;
        let bootstrapModals={createModal:null,deleteModal:null,confirmModal:null};
        const TOKEN_KEY='qtun_auth_token';
        function saveToken(e){localStorage.setItem(TOKEN_KEY,e)}
        function getToken(){return localStorage.getItem(TOKEN_KEY)}
        function clearToken(){localStorage.removeItem(TOKEN_KEY)}
        function enforcePageVisibility(){document.querySelectorAll('.page').forEach(e=>{e.style.display=e.classList.contains('active')?'block':'none'})}
        function autoLogin(){const e=getToken();if(!e){enforcePageVisibility();document.getElementById('login-username').focus();return}
            apiCall('verify_token',{token:e},t=>{
                if(t.success){currentUser=t.username;document.getElementById('page-login').classList.remove('active');document.getElementById('sidebarMenu').classList.remove('d-none');document.getElementById('topNavbar').classList.remove('d-none');showPage('dashboard')}
                else{clearToken();enforcePageVisibility();document.getElementById('sidebarBackdrop').classList.remove('show')}
                enforcePageVisibility()
            },true)}
        function initSidebar(){const e=document.getElementById('sidebarMenu'),t=document.getElementById('sidebarBackdrop'),n=document.getElementById('sidebarToggle'),o=document.getElementById('sidebarClose');function s(){e.classList.add('show'),t.classList.add('show')}function a(){e.classList.remove('show'),t.classList.remove('show')}n&&n.addEventListener('click',s),o&&o.addEventListener('click',a),t&&t.addEventListener('click',a);document.querySelectorAll('#sidebarMenu .nav-link[data-page]').forEach(e=>{e.addEventListener('click',()=>{window.innerWidth<768&&a()})})}
        function enterFullscreenClash(){document.getElementById('sidebarMenu').classList.add('d-none');document.getElementById('topNavbar').classList.add('d-none');document.getElementById('mainContent').classList.add('d-none');document.getElementById('clashTopbar').classList.add('show')}
        function exitFullscreenClash(){document.getElementById('sidebarMenu').classList.remove('d-none');document.getElementById('topNavbar').classList.remove('d-none');document.getElementById('mainContent').classList.remove('d-none');document.getElementById('clashTopbar').classList.remove('show');document.getElementById('sidebarBackdrop').classList.remove('show');const e=document.querySelector('.clash-frame');e&&e.remove()}
        function showPage(e){if('dashboard'!==e&&(refreshLogInterval&&clearInterval(refreshLogInterval),refreshStatusInterval&&clearInterval(refreshStatusInterval)),e==='clash'){enterFullscreenClash();reloadClashUI();return}else{exitFullscreenClash()}document.querySelectorAll('.page').forEach(e=>{e.classList.remove('active'),e.style.display='none'});const t=document.getElementById('page-'+e);t&&(t.classList.add('active'),t.style.display='block');document.querySelectorAll('#sidebarMenu .nav-link').forEach(t=>{t.classList.remove('active'),t.dataset.page===e&&t.classList.add('active')});'dashboard'===e?(refreshStatus(),refreshLogs(),refreshStatusInterval=setInterval(refreshStatus,5e3),refreshLogInterval=setInterval(refreshLogs,3e3)):'configs'===e?refreshConfigList():'users'===e&&refreshUserList()}
        function doLogin(){const e=document.getElementById('login-username').value.trim(),t=document.getElementById('login-password').value;if(!e||!t)return showAlert('login-error','Username and password required','danger');const n=document.getElementById('loginBtn');setBtnLoading(n,!0);apiCall('login',{username:e,password:t},o=>{setBtnLoading(n,!1);if(o.success){currentUser=o.username;saveToken(o.token);document.getElementById('page-login').classList.remove('active');document.getElementById('sidebarMenu').classList.remove('d-none');document.getElementById('topNavbar').classList.remove('d-none');showPage('dashboard')}else showAlert('login-error',o.message||'Login failed','danger');enforcePageVisibility()})}
        function logout(){confirmAction('Logout?',()=>{const e=getToken();e&&apiCall('logout',{token:e},()=>{});clearToken();currentUser=null;refreshLogInterval&&clearInterval(refreshLogInterval);refreshStatusInterval&&clearInterval(refreshStatusInterval);exitFullscreenClash();document.querySelectorAll('.modal.show').forEach(e=>{bootstrap.Modal.getInstance(e)?.hide()});document.querySelectorAll('.page').forEach(e=>{e.classList.remove('active'),e.style.display='none'});document.getElementById('page-login').classList.add('active');document.getElementById('page-login').style.display='block';document.getElementById('sidebarMenu').classList.add('d-none');document.getElementById('topNavbar').classList.add('d-none');document.getElementById('login-username').value='';document.getElementById('login-password').value='';document.getElementById('sidebarBackdrop').classList.remove('show')})}
        function confirmAction(e,t){document.getElementById('confirm-action-message').textContent=e;const n=document.getElementById('confirm-action-ok');n.onclick=()=>{bootstrapModals.confirmModal.hide();t()};bootstrapModals.confirmModal.show()}
        function setBtnLoading(e,t){if(!e)return;if(t){e.classList.add('btn-loading');e.disabled=!0}else{e.classList.remove('btn-loading');e.disabled=!1}}
        function apiCall(e,t,n,keepTokenOnError=false){let o=window.location.href.split('?')[0],s='';e.includes('?')&&([e,s]=e.split('?'),s='&'+s),o+='?api='+e+s;const a={method:t?'POST':'GET',headers:{'Content-Type':'application/json',Accept:'application/json'}};t&&(a.body=JSON.stringify(t));fetch(o,a).then(e=>e.json()).then(e=>n(e)).catch(e=>{if(!keepTokenOnError)n({success:!1,message:'Network error'});else console.error('Token verify network error')})}
        function showAlert(e,t,n='danger'){const o=document.getElementById(e);o&&(o.textContent=t,o.className='alert alert-'+n,o.classList.remove('d-none'),setTimeout(()=>o.classList.add('d-none'),5e3))}
        function refreshStatus(){apiCall('status',null,e=>{if(e.success){const t=document.getElementById('status-dot'),n=document.getElementById('status-text'),o=document.getElementById('status-reason');t.className='status-dot '+(e.status==='Online'?'bg-success':'bg-secondary');n.textContent=e.status;o.textContent=e.reason}})}
        function refreshLogs(){apiCall('logs',{lines:100},e=>{if(e.success){const t=document.getElementById('log-content');t.textContent=e.logs;t.scrollTop=t.scrollHeight}else document.getElementById('log-error').textContent=e.message,document.getElementById('log-error').classList.remove('d-none')})}
        function doAction(e){const t=document.getElementById('btn-'+e);setBtnLoading(t,!0);apiCall('action',{action:e},n=>{setBtnLoading(t,!1);n.success&&(refreshStatus(),refreshLogs())})}
        function refreshConfigList(){apiCall('configs',null,e=>{if(e.success){const t=document.getElementById('configs-list');t.innerHTML='';if(0===e.configs.length)return void(t.innerHTML='<p class="text-muted">No config files found</p>');e.configs.forEach(e=>{const n=document.createElement('div');n.className='list-group-item config-item d-flex justify-content-between align-items-center';n.onclick=()=>selectConfig(e.name);n.innerHTML=`<div><strong>${e.name}</strong>${e.is_active?' <span class="badge bg-warning ms-2">IN USE</span>':''}<br><small class="text-muted">${Math.round(e.size/1024)} KB &middot; ${e.modified}</small></div>`;t.appendChild(n)})}})}
        function selectConfig(e){currentConfigFile=e;document.querySelectorAll('.config-item').forEach(e=>e.classList.remove('active'));event.currentTarget.classList.add('active');document.getElementById('editor-title').textContent=e;document.getElementById('editor-actions').style.display='';apiCall('configs',{action:'read',filename:e},t=>{if(t.success){isConfigActive=t.is_active;document.getElementById('config-editor').value=t.content;document.getElementById('config-editor').disabled=isConfigActive;document.getElementById('btn-save-config').disabled=isConfigActive;document.getElementById('btn-delete-config').disabled=isConfigActive;isConfigActive?document.getElementById('editor-info').classList.add('show'):document.getElementById('editor-info').classList.remove('show')}else showAlert('editor-error',t.message,'danger')})}
        function saveCurrentConfig(){if(currentConfigFile&&!isConfigActive){const e=document.getElementById('config-editor').value,t=document.getElementById('btn-save-config');setBtnLoading(t,!0);apiCall('configs',{action:'edit',filename:currentConfigFile,content:e},n=>{setBtnLoading(t,!1);n.success?(showAlert('configs-success',n.message,'success'),refreshConfigList()):showAlert('editor-error',n.message,'danger')})}}
        function reloadCurrentConfig(){currentConfigFile&&selectConfig(currentConfigFile)}
        function deleteCurrentConfig(){if(!currentConfigFile||isConfigActive)return showAlert('editor-error','Cannot delete active config','warning');document.getElementById('delete-filename').textContent=currentConfigFile;document.getElementById('confirm-delete-btn').onclick=()=>{const e=document.getElementById('confirm-delete-btn');setBtnLoading(e,!0);apiCall('configs',{action:'delete',filename:currentConfigFile},t=>{setBtnLoading(e,!1);if(t.success){bootstrapModals.deleteModal.hide();refreshConfigList();currentConfigFile=null;isConfigActive=!1;document.getElementById('editor-title').textContent='Select a config file';document.getElementById('editor-actions').style.display='none';document.getElementById('config-editor').value='';document.getElementById('config-editor').disabled=!0;document.getElementById('editor-info').classList.remove('show');showAlert('configs-success','Config deleted','success')}else showAlert('configs-error',t.message,'danger')})};bootstrapModals.deleteModal.show()}
        function openCreateModal(){bootstrapModals.createModal.show()}
        function createNewConfig(){const e=document.getElementById('new-filename').value.trim();if(!e)return showAlert('create-error','Filename required','danger');const t=JSON.stringify({example:'value'},null,2),n=document.getElementById('btn-create-config');setBtnLoading(n,!0);apiCall('configs',{action:'create',filename:e,content:t},o=>{setBtnLoading(n,!1);o.success?(bootstrapModals.createModal.hide(),document.getElementById('new-filename').value='',refreshConfigList(),showAlert('configs-success',o.message,'success')):showAlert('create-error',o.message,'danger')})}
        function reloadClashUI(){const e=document.querySelector('.clash-frame');e&&e.remove();const t=document.createElement('iframe');t.className='clash-frame';t.src='about:blank';document.body.appendChild(t);apiCall('host',null,n=>{if(n.success){const o='http://'+n.host+':9090/ui';t.src=o}else{t.remove();const e=document.getElementById('clash-container');e.innerHTML='<p class="text-danger">Failed to load Clash Dashboard.</p>'}})}
        function refreshUserList(){apiCall('users',null,e=>{if(e.success){const t=document.getElementById('users-list');t.innerHTML='';e.users.forEach(e=>{const n=document.createElement('div');n.className='d-flex align-items-center justify-content-between mb-2 p-2 bg-light rounded';n.innerHTML=`<span><strong>${e.username}</strong> <span class="badge ${e.role==='admin'?'bg-danger':'bg-primary'}">${e.role}</span></span>${e.username!=='admin'?`<button class="btn btn-sm btn-outline-danger" onclick="deleteUser('${e.username}')"><i class="bi bi-x"></i></button>`:''}`;t.appendChild(n)})}})}
        function addUser(){const e=document.getElementById('new-username').value.trim(),t=document.getElementById('new-password').value;if(!e||!t)return showAlert('users-error','Username and password required','danger');const n=document.getElementById('btn-add-user');setBtnLoading(n,!0);apiCall('users',{action:'add',username:e,password:t},o=>{setBtnLoading(n,!1);o.success?(document.getElementById('new-username').value='',document.getElementById('new-password').value='',refreshUserList(),showAlert('users-success',o.message,'success')):showAlert('users-error',o.message,'danger')})}
        function deleteUser(e){confirmAction(`Delete user ${e}?`,()=>{apiCall('users',{action:'delete',username:e},t=>{t.success?(refreshUserList(),showAlert('users-success',t.message,'success')):showAlert('users-error',t.message,'danger')})})}
        function changePassword(){const e=document.getElementById('old-pass').value,t=document.getElementById('new-pass').value;if(!e||!t)return showAlert('users-error','Old and new password required','danger');const n=document.getElementById('btn-change-pass');setBtnLoading(n,!0);apiCall('users',{action:'changepass',username:currentUser,old_password:e,new_password:t},o=>{setBtnLoading(n,!1);o.success?(document.getElementById('old-pass').value='',document.getElementById('new-pass').value='',showAlert('users-success',o.message,'success')):showAlert('users-error',o.message,'danger')})}
        document.addEventListener('DOMContentLoaded',()=>{
            bootstrapModals.createModal=new bootstrap.Modal(document.getElementById('create-modal'));
            bootstrapModals.deleteModal=new bootstrap.Modal(document.getElementById('delete-modal'));
            bootstrapModals.confirmModal=new bootstrap.Modal(document.getElementById('confirm-action-modal'));
            initSidebar();
            document.querySelectorAll('#sidebarMenu .nav-link[data-page]').forEach(e=>{e.addEventListener('click',t=>{t.preventDefault();const n=e.dataset.page;n&&showPage(n)})});
            document.getElementById('logoutBtn').addEventListener('click',e=>{e.preventDefault();logout()});
            document.getElementById('clashBackBtn').addEventListener('click',()=>{showPage('dashboard')});
            enforcePageVisibility();
            autoLogin();
            if(!getToken()) document.getElementById('login-username').focus();
        });
    </script>
</body>
</html>